sql:
SELECT AVG(attendance) AS average_attendance
FROM games
WHERE arena = 'Staples Center' AND season = 2019;

external_knowledge:
- A 'higher-than-average attendance' refers to an attendance greater than the average attendance of all games in the league; 
- A 'home team score above 100 points' refers to a game where the score of the home team is greater than 100.
- 'Average attendance' is calculated based on the attendance of all games in the league.

sql:
SELECT AVG(g.attendance) AS average_attendance
FROM games g
WHERE g.season = 2019 AND (
  (g.home_team = 'TeamA' AND g.home_team_score > g.away_team_score) OR
  (g.away_team = 'TeamA' AND g.away_team_score > g.home_team_score)
);
